function transform(message, context) {
  const currentTermCode = message.payload.termCode;
  let termCodes = message.payload.resTermCodes;
  let firstTermFlag = false;
  
  let previousTermCode = null;

  if (!termCodes?.length) {
    message.payload.flag = false;
    message.payload.previousTermCode = null;
    return message;
  }

  termCodes.sort((a, b) => a.termCode - b.termCode);
  termCodes = termCodes.filter(term => term.termCode> '202000');
  
  for (let term of termCodes) {
    if (term.termCode === currentTermCode) break;
    previousTermCode = term.termCode;
  }
  
  firstTermFlag = previousTermCode === null;
  
  message.payload.firstTermFlag = firstTermFlag;
  message.payload.previousTermCode = previousTermCode;
  message.payload.flag = previousTermCode !== null;
  message.payload.resTermCodes = undefined;
  
  return message;
}

function transform(message, context) {
  const studentGpaResponse = message.payload?.resStudentGpa;

  if (!studentGpaResponse || !Array.isArray(studentGpaResponse)) {
    message.payload.resStudentGpa = undefined;
    return message;
  }

  const termCode = Number(message.payload.termCode);

  // ---------- Helper: calculate CGPA up to a given term ----------
  function calculateCgpa(uptoTerm) {
    let totalQualityPoints = 0;
    let totalGpaHours = 0;

    for (const gpaObj of studentGpaResponse) {
      const gpaTerm = Number(gpaObj.termCode);

      if (
        gpaObj.levlCode === "UG" &&
        gpaTerm > 202500 &&
        gpaTerm <= uptoTerm
      ) {
        totalQualityPoints += Number(gpaObj.qualityPoints || 0);
        totalGpaHours += Number(gpaObj.gpaHours || 0);
      }
    }

    if (totalGpaHours > 0) {
      return Number(totalQualityPoints / totalGpaHours).toFixed(2);
    }

    return null;
  }

  // ---------- Term GPA (current term only) ----------
  let termGpa =
    studentGpaResponse.find(
      gpa =>
        Number(gpa.termCode) === termCode &&
        gpa.levlCode === "UG"
    )?.gpa ?? "N/A";

  if (termGpa !== "N/A") {
    termGpa = Number(termGpa).toFixed(2);
  }

  // ---------- Current CGPA ----------
  const currentCgpa = calculateCgpa(termCode);

  // ---------- Previous valid term (>202500 and < current) ----------
  const previousTermCode = Math.max(
    ...studentGpaResponse
      .map(g => Number(g.termCode))
      .filter(t => t > 202500 && t < termCode)
  );

  const previousCgpa =
    Number.isFinite(previousTermCode)
      ? calculateCgpa(previousTermCode)
      : null;

  // ---------- CGPA Difference ----------
  let cgpaDifference = 0;
  if (currentCgpa !== null && previousCgpa !== null) {
    cgpaDifference = Number(currentCgpa - previousCgpa).toFixed(2);
  }

  // ---------- Set outputs ----------
  message.payload.termGpa = termGpa;
  message.payload.cumulativeGpa = currentCgpa ?? "0.00";
  message.payload.previousCumulativeGpa = previousCgpa ?? "0.00";
  message.payload.cgpaDifference = cgpaDifference;

  context.set("cumulativeGpa", message.payload.cumulativeGpa);

  // ---------- Cleanup ----------
  message.payload.resStudentGpa = undefined;
  return message;
}

function calculateAverageAttendanceFromTerm(termInformation){
  let attendancePercentage = 0;
  
  let sumAttendHr = 0;
  let sumMeetingDays = 0;
  
  for (let term of termInformation){
    sumAttendHr += parseFloat(term.attendHr);
    sumMeetingDays += parseFloat(term.meetingDays);
  }
  
  if (sumMeetingDays !== 0){
    attendancePercentage = sumAttendHr * 100 / sumMeetingDays;
  }

  return attendancePercentage;
}

function transform (message, context) {
  const termInformation = message.payload.termInformation;
  const previousTermInformation = message.payload.previousTermInformation;
  
  const currentAverageAttendance = calculateAverageAttendanceFromTerm(termInformation);
  
  let previousAverageAttendance =
    previousTermInformation
      ? calculateAverageAttendanceFromTerm(previousTermInformation)
      : 0;
  
  // const differenceInAttendance = (previousAverageAttendance == 0) ? 0 : (currentAverageAttendance - previousAverageAttendance);
  const differenceInAttendance = (currentAverageAttendance - previousAverageAttendance).toFixed(2);
  
  message.payload.differenceInAttendance = differenceInAttendance;
  message.payload.averageAttendancePercentage = currentAverageAttendance.toFixed(2);
  
  // message.payload.termInformation = undefined;
  message.payload.previousTermInformation = undefined;
  
  return message;
}
